const WARNING_PERCENT  = 33.0;
const CRITICAL_PERCENT = 15.0;

const distance = msg.payload.distance_cm;

const fullDist  = flow.get('calibFullDist')  || 20.4;
const emptyDist = flow.get('calibEmptyDist') || 43.0;
const clamped   = Math.max(fullDist, Math.min(emptyDist, distance));
const percent   = Math.round(100 * (emptyDist - clamped) / (emptyDist - fullDist));

let criticalSent = flow.get('criticalSent') || false;
let warningSent  = flow.get('warningSent')  || false;
let testMode     = flow.get('testMode')     || false;

if (testMode && !msg._fromTest) {
    return null;
}
if (msg._fromTest && !testMode) {
    return null;
}

node.status({ fill: 'blue', shape: 'dot',
    text: `${percent}% / ${distance}cm` });

let status = 'ok';
let haCommands = [];
let notifyMessages = [];

if (percent < CRITICAL_PERCENT) {
    status = 'critical';
    if (!criticalSent) {
        haCommands.push({ entity: 'switch.salt_critical_alert', state: true });
        criticalSent = true;
        node.warn('CRITICAL alert sent');
        notifyMessages.push({ payload: `CRITICAL — salt at ${percent}%. Alert sent to SmartThings.` });
    }
    if (warningSent) {
        haCommands.push({ entity: 'switch.salt_low_alert', state: false });
        warningSent = false;
        notifyMessages.push({ payload: '[System] Warning alert cleared.' });
    }
} else if (percent <= WARNING_PERCENT) {
    status = 'warning';
    if (!warningSent) {
        haCommands.push({ entity: 'switch.salt_low_alert', state: true });
        warningSent = true;
        node.warn('WARNING alert sent');
        notifyMessages.push({ payload: `WARNING — salt at ${percent}%. Alert sent to SmartThings.` });
    }
    if (criticalSent) {
        haCommands.push({ entity: 'switch.salt_critical_alert', state: false });
        criticalSent = false;
        notifyMessages.push({ payload: '[System] Critical alert cleared.' });
    }
} else {
    if (criticalSent) {
        haCommands.push({ entity: 'switch.salt_critical_alert', state: false });
        criticalSent = false;
        notifyMessages.push({ payload: '[System] Critical alert cleared — salt level OK.' });
    }
    if (warningSent) {
        haCommands.push({ entity: 'switch.salt_low_alert', state: false });
        warningSent = false;
        notifyMessages.push({ payload: '[System] Warning alert cleared — salt level OK.' });
    }
}

flow.set('criticalSent', criticalSent);
flow.set('warningSent',  warningSent);

const statusMsg = { payload: status, topic: 'jctsh/sensors/salt-sensor/status' };
const haMessages = haCommands.map(cmd => ({ payload: cmd }));

return [statusMsg, haMessages.length > 0 ? haMessages : null, notifyMessages.length > 0 ? notifyMessages : null];

const text = String(msg.payload);

let category = 'System';
let message = text;

if (text.startsWith('[TEST]')) {
    category = 'Test';
    message = text.slice(7).trim();
} else if (text.startsWith('[ERROR]')) {
    category = 'System';
    message = text.slice(8).trim();
} else if (text.startsWith('[System]')) {
    category = 'System';
    message = text.slice(9).trim();
} else if (text.startsWith('[MQTT]')) {
    category = 'MQTT';
    message = text.slice(7).trim();
} else if (text.indexOf('CRITICAL') >= 0 || text.indexOf('WARNING') >= 0) {
    category = 'Alert';
}

msg.payload = JSON.stringify({
    component: 'salt-sensor',
    category: category,
    message: message
});
return msg;

const HA_URL   = 'http://localhost:8123';
const HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken') || global.get('haToken');

const cmd    = msg.payload;
const action = cmd.state ? 'turn_on' : 'turn_off';

msg.url     = `${HA_URL}/api/services/switch/${action}`;
msg.method  = 'POST';
msg.headers = {
    'Authorization': 'Bearer ' + HA_TOKEN,
    'Content-Type': 'application/json'
};
msg.payload = JSON.stringify({ entity_id: cmd.entity });
return msg;

if (msg.statusCode !== 200 && msg.statusCode !== 207) {
    node.warn('HA API error ' + msg.statusCode + ': ' + msg.payload);
    return [null, { payload: '[ERROR] HA API error ' + msg.statusCode + ' — alerts may not have reached SmartThings.' }];
}
return null;

const HA_URL   = 'http://localhost:8123';
const HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken') || global.get('haToken');

const headers = {
    'Authorization': 'Bearer ' + HA_TOKEN
};

return [
    { payload: null, url: `${HA_URL}/api/states/switch.salt_test_mode`,
      method: 'GET', headers, _check: 'testmode' },
    { payload: null, url: `${HA_URL}/api/states/switch.salt_full_reset`,
      method: 'GET', headers, _check: 'reset' },
    { payload: null, url: `${HA_URL}/api/states/input_number.salt_full_distance_cm`,
      method: 'GET', headers, _check: 'full_dist' },
    { payload: null, url: `${HA_URL}/api/states/input_number.salt_empty_distance_cm`,
      method: 'GET', headers, _check: 'empty_dist' }
];

if (msg.statusCode !== 200) return null;

const state = msg.payload.state;
const check = msg._check;

if (check === 'testmode') {
    const wasOn = flow.get('testMode') || false;
    const isOn  = (state === 'on');
    if (isOn !== wasOn) {
        flow.set('testMode', isOn);
        node.warn('Test mode: ' + (isOn ? 'ON' : 'OFF'));
        if (!isOn) {
            flow.set('testStep', 0);
            flow.set('criticalSent', false);
            flow.set('warningSent', false);
            node.warn('Test mode OFF — clearing HA alert switches, publishing ok to ESP32');
            node.status({ fill: 'grey', shape: 'ring', text: 'test mode off' });
            return [
                { payload: 'reset' },
                { payload: 'ok', topic: 'jctsh/sensors/salt-sensor/status' },
                [
                    { payload: '[System] ─────────────────────────────────────' },
                    { payload: '[System] TEST MODE OFF' },
                    { payload: '[System] Normal operational mode restored.' },
                    { payload: '[System] Readings resume on 12-hour schedule.' },
                    { payload: '[System] ─────────────────────────────────────' }
                ]
            ];
        }
        node.status({ fill: 'blue', shape: 'dot', text: 'test mode on' });
        return [null, null, { payload: '[TEST] TEST MODE ON — simulating salt levels at 1s intervals' }];
    }

} else if (check === 'reset') {
    const alertActive = flow.get('criticalSent') || flow.get('warningSent');
    if (state === 'on' && alertActive) {
        node.warn('Reset switch ON — triggering alert cleanup');
        return [{ payload: 'reset' }, null, null];
    }

} else if (check === 'full_dist') {
    const val = parseFloat(state);
    if (!isNaN(val) && val > 0) flow.set('calibFullDist', val);

} else if (check === 'empty_dist') {
    const val = parseFloat(state);
    if (!isNaN(val) && val > 0) flow.set('calibEmptyDist', val);
}

return null;

if (!flow.get('testMode')) return null;

const step = flow.get('testStep') || 0;
if (step >= 2) return null;

const FULL  = flow.get('calibFullDist')  || 20.4;
const EMPTY = flow.get('calibEmptyDist') || 43.0;

let distance, label;
if (step === 0) {
    distance = EMPTY - 0.27 * (EMPTY - FULL);
    label = 'Step 1/2: WARNING zone';
} else {
    distance = EMPTY;
    label = 'Step 2/2: CRITICAL zone';
}

const percent = Math.round(100 * (EMPTY - distance) / (EMPTY - FULL));
flow.set('testStep', step + 1);

node.warn(`TEST MODE ${label} — ${percent}%`);

return [
    { payload: { distance_cm: distance }, _fromTest: true },
    { payload: `[TEST] ${label} — ${distance.toFixed(1)}cm / ${percent}%` }
];

const HA_URL   = 'http://localhost:8123';
const HA_TOKEN = env.get('HA_TOKEN') || flow.get('haToken') || global.get('haToken');

const headers = {
    'Authorization': 'Bearer ' + HA_TOKEN,
    'Content-Type': 'application/json'
};

flow.set('criticalSent', false);
flow.set('warningSent',  false);
node.warn('Reset triggered - clearing all alerts');

return [
    [
        { payload: JSON.stringify({ entity_id: 'switch.salt_critical_alert' }),
          url: `${HA_URL}/api/services/switch/turn_off`,
          method: 'POST', headers },
        { payload: JSON.stringify({ entity_id: 'switch.salt_low_alert' }),
          url: `${HA_URL}/api/services/switch/turn_off`,
          method: 'POST', headers },
        { payload: JSON.stringify({ entity_id: 'switch.salt_full_reset' }),
          url: `${HA_URL}/api/services/switch/turn_off`,
          method: 'POST', headers }
    ],
    { payload: '[System] Reset acknowledged — all alerts cleared.' }
];
